/**
 * SPEC-020: Capturas — la búsqueda global (⌘K) con hits de capturas sin
 * empresa: contexto "Sin empresa" y navegación a /captures/:id (los hits con
 * empresa conservan su ruta anidada, cubierta por SPEC-018 AC-15).
 * Generated by QA Dev agent.
 *
 * Mismo arnés que GlobalSearch.test.tsx: TopBar FUERA de las Routes con
 * probes de destino; api.db.search mockeado; debounce real de 150 ms →
 * findBy/waitFor; scoping por grupo de cmdk.
 */
import { render, screen, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { TopBar } from '@/components/layout/TopBar'
import type { SearchResults } from '@/types/search'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

let mockApi: MockApiHandle

/** Un hit de captura sin empresa y otro con empresa (contraste de contexto). */
const RESULTS: SearchResults = {
  discoveries: [],
  companies: [],
  contacts: [],
  interviews: [
    {
      id: 'i-1',
      title: 'Captura de dolor suelta',
      companyId: null,
      discoveryId: 'd-1',
      companyName: null,
      status: 'draft'
    },
    {
      id: 'i-2',
      title: 'Entrevista de dolor con Acme',
      companyId: 'c-1',
      discoveryId: 'd-1',
      companyName: 'Acmé Córp',
      status: 'recorded'
    }
  ]
}

function renderTopBar(): RenderResult {
  return render(
    <MemoryRouter initialEntries={['/captures']}>
      <TopBar />
      <Routes>
        <Route path="/captures" element={<div>HOME_PROBE</div>} />
        <Route path="/captures/:id" element={<div>CAPTURE_PROBE</div>} />
        <Route
          path="/discoveries/:discoveryId/companies/:companyId/interviews/:interviewId"
          element={<div>INTERVIEW_PROBE</div>}
        />
      </Routes>
    </MemoryRouter>
  )
}

async function openSearch(user: ReturnType<typeof userEvent.setup>): Promise<HTMLElement> {
  await user.click(screen.getByRole('button', { name: 'Buscar' }))
  await screen.findByRole('dialog')
  return screen.getByPlaceholderText('Buscar…')
}

/** Grupo de cmdk por su heading (scoping obligatorio: los contextos se repiten). */
async function findGroup(heading: string): Promise<HTMLElement> {
  const headingNode = await screen.findByText(heading)
  const group = headingNode.closest('[cmdk-group]')
  if (group === null) {
    throw new Error(`El heading ${heading} debe pertenecer a un grupo de cmdk`)
  }
  return group as HTMLElement
}

beforeEach(() => {
  vi.clearAllMocks()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.search).mockResolvedValue({ ok: true, data: RESULTS })
})

describe('GlobalSearch (SPEC-020 capturas)', () => {
  // SPEC-020 · AC-34
  it('shows "Sin empresa" as the context of a companyless capture hit and navigates to /captures/:id on click', async () => {
    const user = userEvent.setup()
    renderTopBar()
    const input = await openSearch(user)

    await user.type(input, 'dolor')

    const group = await findGroup('Entrevistas')
    // El hit sin empresa muestra "Sin empresa"; el hit con empresa, su nombre
    expect(within(group).getByText('Captura de dolor suelta')).toBeInTheDocument()
    expect(within(group).getByText('Sin empresa')).toBeInTheDocument()
    expect(within(group).getByText('Acmé Córp')).toBeInTheDocument()

    await user.click(within(group).getByText('Captura de dolor suelta'))

    expect(await screen.findByText('CAPTURE_PROBE')).toBeInTheDocument()
    expect(screen.queryByRole('dialog')).not.toBeInTheDocument()
  })

  // SPEC-020 · AC-34 (refuerzo: los hits CON empresa conservan su ruta anidada)
  it('keeps the nested interview route for hits that do have a company', async () => {
    const user = userEvent.setup()
    renderTopBar()
    const input = await openSearch(user)

    await user.type(input, 'dolor')

    const group = await findGroup('Entrevistas')
    await user.click(within(group).getByText('Entrevista de dolor con Acme'))

    expect(await screen.findByText('INTERVIEW_PROBE')).toBeInTheDocument()
  })
})
